// n8n Code Node вҖ“ LINKEDIN INFO (VersГЈo Turbo SEM TRADUГҮГғO)
// Limpa, organiza, classifica lideranГ§a e mantГ©m os textos originais SEM traduГ§ГЈo.

// --- Helpers ---------------------------------------------------------
const parseNumber = (str) => {
  if (!str) return null;
  if (typeof str === "number") return str;
  const only = String(str).replace(/[^\d]/g, "");
  return only ? Number(only) : null;
};

const classifyRole = (title = "") => {
  const t = title.toLowerCase();

  if (t.includes("ceo") || t.includes("chief executive")) return "C-Level";
  if (t.includes("founder") || t.includes("co-founder")) return "C-Level";
  if (t.includes("president") || t.includes("chairman")) return "C-Level";
  if (t.includes("cfo") || t.includes("cto") || t.includes("cio")) return "C-Level";

  if (t.includes("director") || t.includes("diretor")) return "Director";
  if (t.includes("head")) return "Head";
  if (t.includes("manager") || t.includes("gerente")) return "Manager";
  if (t.includes("lead") || t.includes("lГӯder")) return "Lead";

  return "Staff";
};

const roleScore = {
  "C-Level": 5,
  "Director": 4,
  "Head": 3,
  "Manager": 2,
  "Lead": 1,
  "Staff": 0,
};

// --- Entrada bruta ---------------------------------------------------
let raw = $input.all().map(i => i.json);
if (raw.length === 1) raw = raw[0];
if (raw?.output) try { raw = JSON.parse(raw.output); } catch {}
if (typeof raw === "string") try { raw = JSON.parse(raw); } catch {}

const company = Array.isArray(raw) ? raw[0] : raw;

if (!company || typeof company !== "object") {
  return [{ json: { source_type: "linkedin_info", linkedin_info: raw }}];
}

// --- Employees + lideranГ§a -------------------------------------------
let employees = Array.isArray(company.employees) ? company.employees : [];

const cleanEmployees = employees.map(emp => {
  const lvl = classifyRole(emp.role || "");
  return {
    name: emp.name || null,
    role: emp.role || null,  // sem traduГ§ГЈo
    profile_url: emp.profile_url || null,
    decision_level: lvl,
    relevance_score: roleScore[lvl] || 0
  };
});

const leadership = cleanEmployees
  .filter(e => e.relevance_score >= 3)
  .sort((a, b) => b.relevance_score - a.relevance_score)
  .slice(0, 10);

// --- Similar companies ------------------------------------------------
const similar = Array.isArray(company.similar_pages)
  ? company.similar_pages.map(sp => ({
      name: sp.name || null,
      industry: sp.industry || "",
      location: sp.location || null,
      url: sp.url || null,
      logo_url: sp.logo_url || null
    }))
  : [];

// --- ConstruГ§ГЈo final sem traduГ§ГЈo -----------------------------------
const clean = {
  name: company.name || null,
  industry: company.industry || company.about_industry || "",
  description: company.description || company.info || "",
  short_description: company.info || "",
  tagline: company.tagline || "",

  website: company.website || null,
  url: company.formatted_url || company.url || null,

  followers: parseNumber(company.followers),
  company_size: company.company_size || null,
  employee_count: parseNumber(company.employee_count) || null,
  company_type: company.company_type || null,

  headquarters: company.headquarters || company.location || null,
  founded: company.founded || null,
  country_code: company.country_code || null,

  specialties: Array.isArray(company.specialties)
    ? company.specialties
    : [],

  all_locations: Array.isArray(company.all_locations)
    ? company.all_locations
    : [],

  logoUrl: company.profile_pic_url || null,
  background_cover_image_url: company.background_cover_image_url || null,

  similar_companies: similar,
  leadership,
  employees: cleanEmployees.slice(0, 50)
};

// ---------------------------------------------------------------------

return [
  {
    json: {
      source_type: "linkedin_info",
      linkedin_info: clean
    }
  }
];

// 1. Pega TODOS os items retornados pelo ator
let rawList = items.map(i => i.json);

// 2. Se algum vier como string вҶ’ parse
rawList = rawList.map(r => {
  if (r?.output) {
    try { return JSON.parse(r.output); } catch { return r.output; }
  }
  if (typeof r === "string") {
    try { return JSON.parse(r); } catch {}
  }
  return r;
});

// 3. Se vier como objeto indexado {0:{},1:{}} вҶ’ vira array
rawList = rawList.flatMap(r => {
  if (r && typeof r === "object" && !Array.isArray(r)) {
    const keys = Object.keys(r);
    const isSeq = keys.every((k, i) => String(i) === k);
    if (isSeq) return Object.values(r);
  }
  return r;
});

// 4. Garantir array
if (!Array.isArray(rawList)) rawList = [rawList];

// 5. Clean final simplificado + stats completos + type
return rawList.map(post => {
  const mediaItem = Array.isArray(post?.media?.items) ? post.media.items[0] : null;

  const cleanPost = {
    id: post.activity_urn || post.full_urn || null,
    text: post.text || "",
    post_type: post.post_type || null,
    posted_at: post.posted_at?.date || null,

    stats: {
      total_reactions: post.stats?.total_reactions ?? 0,
      like: post.stats?.like ?? 0,
      love: post.stats?.love ?? 0,
      celebrate: post.stats?.celebrate ?? 0,
      reposts: post.stats?.reposts ?? 0,
      comments: post.stats?.comments ?? 0
    },

    media: {
      type: post.media?.type || null,
      url: mediaItem?.url || null,
      thumbnail: mediaItem?.thumbnail || null,
      duration: mediaItem?.duration || null
    }
  };

  return {
    json: {
      source_type: "linkedin_posts",
      linkedin_posts: cleanPost
    }
  };
});

// FunГ§ГЈo que decide tipo de mГӯdia, URL principal e thumbnail
function getMediaInfo(post) {
  let mediaType = 'image';
  let mediaUrl = null;
  let thumbnailUrl = null;

  // Se tiver vГӯdeo, prioriza SEMPRE o vГӯdeo como mediaUrl
  if (post.videoUrl) {
    mediaType = 'video';
    mediaUrl = post.videoUrl;

    // Thumbnail do vГӯdeo (pra mostrar preview se quiser)
    if (Array.isArray(post.images) && post.images.length > 0) {
      thumbnailUrl = post.images[0];
    } else if (post.displayUrl) {
      thumbnailUrl = post.displayUrl;
    }
  } else {
    // NГЈo tem vГӯdeo вҶ’ imagem ou carrossel
    if (post.type === 'Sidecar') {
      mediaType = 'carousel';
    } else {
      mediaType = 'image';
    }

    if (Array.isArray(post.images) && post.images.length > 0) {
      mediaUrl = post.images[0];
    } else if (post.displayUrl) {
      mediaUrl = post.displayUrl;
    }
  }

  return { mediaType, mediaUrl, thumbnailUrl };
}

const results = [];

for (const item of items) {
  const raw = Array.isArray(item.json) ? item.json[0] : item.json;
  if (!raw) continue;

  const username = raw.username || null;
  const profileUrl =
    raw.url ||
    raw.inputUrl ||
    (username ? `https://www.instagram.com/${username}` : null);

  const followersCount = raw.followersCount ?? null;
  const followsCount = raw.followsCount ?? null;
  const postsCount = raw.postsCount ?? null;

  const posts = [];

  const latestPosts = Array.isArray(raw.latestPosts) ? raw.latestPosts : [];
  const latestIgtv = Array.isArray(raw.latestIgtvVideos) ? raw.latestIgtvVideos : [];

  // Junta posts e IGTV
  const allPosts = [...latestPosts, ...latestIgtv];

  // Ordena por data (mais recente primeiro), se tiver timestamp
  allPosts.sort((a, b) => {
    const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
    const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
    return tb - ta;
  });

  // рҹ‘ү AGORA USA TODOS OS POSTS (SEM LIMITAR EM 5)
  for (const post of allPosts) {
    const { mediaType, mediaUrl, thumbnailUrl } = getMediaInfo(post);

    posts.push({
      id: post.id || null,
      caption: post.caption || '',
      url: post.url || null,
      mediaType,          // 'image' | 'video' | 'carousel'
      mediaUrl,           // vГӯdeo real (mp4/etc) OU imagem
      thumbnailUrl,       // capa opcional (principalmente pra vГӯdeo)
      likesCount: post.likesCount ?? null,
      commentsCount: post.commentsCount ?? null,
      sharesCount: null,  // Instagram nГЈo expГөe isso direto
      mentions: Array.isArray(post.mentions) ? post.mentions : [],
      hashtags: Array.isArray(post.hashtags) ? post.hashtags : [],
      timestamp: post.timestamp || null,
    });
  }

  const instagram_info = {
    username,
    profileUrl,
    profile: {
      followersCount,
      followsCount,
      postsCount,
    },
    posts,
  };

  results.push({
    json: {
      instagram_info,
    },
  });
}

return results;

// items: saГӯda do ator do YouTube (um item por vГӯdeo)
const all = items.map(i => i.json);

// Se nГЈo tiver vГӯdeo, retorna vazio
if (!all.length) {
  return [];
}

// Usa o primeiro vГӯdeo como base para dados do canal
const base = all[0];

const channel = {
  name: base.channelName,
  url: base.channelUrl,
  totalVideos: base.channelTotalVideos,
  totalViews: base.channelTotalViews,
  subscribers: base.numberOfSubscribers,
};

// Mapeia sГі os campos importantes de cada vГӯdeo
const videos = all.map(v => ({
  id: v.id,
  title: v.title,
  url: v.url,
  thumbnailUrl: v.thumbnailUrl,
  viewCount: v.viewCount,
  likes: v.likes,
  commentsCount: v.commentsCount,
  publishedAt: v.date,
}));

return [
  {
    json: {
      source_type: "youtube_info",
      youtube_info: {
        channel,
        videos,
      },
    },
  },
];

// ===============================
// рҹ§  HELPERS (PADRONIZAГҮГғO)
// ===============================
const ensureArray = (data) => {
  if (!data) return [];
  if (Array.isArray(data)) return data;
  if (typeof data === "object") return [data];
  return [];
};

// рҹ”Ҙ resolver logo linkedin com fallback
const resolveLinkedinLogo = (li) => {
  if (!li) return null;
  return (
    li.logoUrl ||
    li.logo_url ||
    li.profile_pic_url ||
    li.image ||
    li.picture ||
    null
  );
};

// ===============================
// CAMADA 1 вҖ” RAW NORMALIZADO
// ===============================
let linkedin_info = null;
let linkedin_posts = [];

let instagram_info = null;
let instagram_posts = [];

let youtube_info = null;
let glassdoor_info = null;
let blog_posts = [];

let similar_companies = [];
let market_research = null;

// ===============================
// LOOP EM TODOS OS INPUTS
// ===============================
for (const item of items) {
  const b = item.json;

  if (b.market_research_raw && !market_research) {
    market_research = b.market_research_raw;
  }

  if (b.linkedin_info || b.source_type === "linkedin_info") {
    const li = b.linkedin_info || b;

    if (!linkedin_info) linkedin_info = li;

    if (Array.isArray(li.similar_companies)) {
      similar_companies.push(...li.similar_companies);
    }
  }

  if (b.linkedin_posts || b.source_type === "linkedin_posts") {
    const posts = ensureArray(b.linkedin_posts || b.posts);
    linkedin_posts.push(...posts);
  }

  if (b.instagram_info || b.source_type === "instagram_info") {
    const ig = b.instagram_info || b;

    if (!instagram_info) {
      instagram_info = { ...ig };
      delete instagram_info.posts;
    }

    instagram_posts.push(...ensureArray(ig.posts));
  }

  if (b.source_type === "instagram_posts") {
    instagram_posts.push(...ensureArray(b.posts));
  }

  if (b.youtube_info || b.source_type === "youtube") {
    if (!youtube_info) youtube_info = b.youtube_info || b;
  }

  if (b.glassdoor_info || b.source_type === "glassdoor") {
    if (!glassdoor_info) glassdoor_info = b.glassdoor_info || b;
  }

  if (b.blog_posts || b.source_type === "blog_posts") {
    const posts = ensureArray(b.blog_posts || b.posts);
    blog_posts.push(...posts);
  }

  if (Array.isArray(b.similar_companies)) {
    similar_companies.push(...b.similar_companies);
  }
}

// ===============================
// рҹ”Ҙ DEDUPE AVANГҮADO
// ===============================
const dedupe = (arr) => {
  const seen = new Set();

  return arr.filter(item => {
    const key =
      item.id ||
      item.url ||
      item.link ||
      item.name ||
      JSON.stringify(item).slice(0, 100);

    if (seen.has(key)) return false;

    seen.add(key);
    return true;
  });
};

linkedin_posts = dedupe(linkedin_posts);
instagram_posts = dedupe(instagram_posts);
blog_posts = dedupe(blog_posts);
similar_companies = dedupe(similar_companies);

// ===============================
// NORMALIZAГҮГғO SIMILAR
// ===============================
similar_companies = similar_companies.map(c => ({
  name: c.name || null,
  industry: c.industry || null,
  location: c.location || null,
  url: c.url || null,
  logo_url: c.logo_url || c.logo || null,
  source: c.source || "linkedin"
}));

// ===============================
// рҹ§  MERGE INTELIGENTE
// ===============================
let company = {};

if (market_research?.company) {
  const c = market_research.company;

  company = {
    nome: c.nome,
    dominio: c.dominio,
    descricao_institucional: c.descricao_institucional,
    setor: c.setor,
    produtos_servicos: c.produtos_servicos || [],
    diferenciais: c.diferenciais || [],

    tagline: linkedin_info?.tagline ?? null,
    website: linkedin_info?.website ?? c.dominio ?? null,
    linkedin_url: linkedin_info?.linkedin_url ?? null,
    followers: linkedin_info?.followers ?? null,
    company_size: linkedin_info?.company_size ?? null,
    employee_count: linkedin_info?.employee_count ?? null,
    company_type: linkedin_info?.company_type ?? null,
    headquarters: linkedin_info?.headquarters ?? null,
    founded: linkedin_info?.founded ?? null,
    country_code: linkedin_info?.country_code ?? null,

    specialties: [
      ...(c.especialidades || []),
      ...(linkedin_info?.specialties || [])
    ]
  };

  company.specialties = [...new Set(company.specialties)];
}
else if (linkedin_info) {
  company = {
    nome: linkedin_info.name,
    dominio: linkedin_info.website,
    descricao_institucional: linkedin_info.description,
    setor: linkedin_info.industry,
    specialties: linkedin_info.specialties || []
  };
}

// ===============================
// рҹ§  LOGO PRINCIPAL (APENAS ELE)
// ===============================
const linkedin_logo = resolveLinkedinLogo(linkedin_info);

// ===============================
// OUTPUT FINAL
// ===============================
return [
  {
    json: {
      company,
      linkedin_logo, // вң… SOMENTE ELE

      linkedin_posts,
      instagram_info,
      instagram_posts,
      youtube_info,
      glassdoor_info,
      blog_posts,

      similar_companies, // вң… logos continuam aqui dentro (logo_url)

      market_research_raw: market_research
    }
  }
];

// Pegamos tudo que veio do ator (cada item Г© um review do Glassdoor)
const raw = items.map(i => i.json);

// 1) Achar onde estГЈo as estatГӯsticas gerais (ratings, distribuiГ§ГЈo etc)
const statsCarrier = raw.find(r => r?.companyReviewStats?.data?.employerReviewsRG?.ratings);
const stats = statsCarrier?.companyReviewStats?.data;

// 2) Notas gerais da empresa
const ratings = stats?.employerReviewsRG?.ratings || {};

// 3) DistribuiГ§ГЈo das notas (1 a 5 estrelas)
const stars = stats?.employerReviewsRG?.ratingCountDistribution?.overall || {};

// 4) Pegar APENAS UM review com pros/cons/advice (o primeiro que tiver algo Гәtil)
const oneReview = raw.find(r => r?.pros || r?.cons || r?.advice) || {};

// 5) Montar saГӯda limpa, sem nome, cargo, localizaГ§ГЈo, nada pessoal
return [
  {
    json: {
      source_type: "glassdoor_info",
      glassdoor_info: {
        // Notas gerais importantes
        overall_rating: ratings.overallRating ?? null,
        compensation_benefits_rating: ratings.compensationAndBenefitsRating ?? null,
        culture_values_rating: ratings.cultureAndValuesRating ?? null,
        career_opportunities_rating: ratings.careerOpportunitiesRating ?? null,
        work_life_balance_rating: ratings.workLifeBalanceRating ?? null,
        diversity_inclusion_rating: ratings.diversityAndInclusionRating ?? null,
        recommend_to_friend: ratings.recommendToFriendRating ?? null,
        ceo_rating: ratings.ceoRating ?? null,

        // DistribuiГ§ГЈo de estrelas
        rating_distribution: {
          one_star: stars._1 ?? 0,
          two_stars: stars._2 ?? 0,
          three_stars: stars._3 ?? 0,
          four_stars: stars._4 ?? 0,
          five_stars: stars._5 ?? 0
        },

        // Apenas UM exemplo de prГіs, contras e conselho
        pros_example: oneReview.pros || null,
        cons_example: oneReview.cons || null,
        advice_example: oneReview.advice || null
      }
    }
  }
];

