// 1. Capturar o texto vindo do agente (string JSON)
const raw =
  items[0].json?.response?.generations?.[0]?.[0]?.text ||
  items[0].json?.response?.generations?.[0]?.text ||
  items[0].json?.output ||
  items[0].json?.response ||
  null;

if (!raw) {
  return [{
    json: { news_research_raw: null, _error: "Sem conteГәdo para parsear" }
  }];
}

// 2. Limpeza dos blocos ```json / ```
let cleaned = raw
  .trim()
  .replace(/```json/gi, "")
  .replace(/```javascript/gi, "")
  .replace(/```JSON/gi, "")
  .replace(/```/g, "")
  .trim();

// 3. Remover caracteres invisГӯveis problemГЎticos
cleaned = cleaned.replace(/\u00A0/g, " "); // NBSP
cleaned = cleaned.replace(/\u200B/g, ""); // Zero-width

// 4. Tentar converter para JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  return [{
    json: {
      news_research_raw: cleaned,
      _error: "JSON.parse falhou",
      _details: err.message
    }
  }];
}

// 5. Extrair corretamente o objeto final
let finalData = parsed.news_research_raw ? parsed.news_research_raw : parsed;

// 6. Garantir que news_and_updates seja array
if (finalData?.news_and_updates && !Array.isArray(finalData.news_and_updates)) {
  finalData.news_and_updates = [finalData.news_and_updates];
}

// 7. Garantir que references seja sempre array
if (finalData?.references && !Array.isArray(finalData.references)) {
  finalData.references = [finalData.references];
}

// 8. Retorno final
return [{
  json: {
    news_research_raw: finalData
  }
}];

