parameters.jsCode:
// 1. Capturar o texto vindo do agente (string JSON)
let raw =
  items[0].json?.response?.generations?.[0]?.[0]?.text ||
  items[0].json?.response?.generations?.[0]?.text ||
  items[0].json?.output ||
  items[0].json?.response ||
  null;

// 2. ValidaГ§ГЈo inicial
if (!raw) {
  return [{
    json: {
      market_research_raw: null,
      _error: "Sem conteГәdo para parsear"
    }
  }];
}

// рҹ”Ҙ HARDEN 1 вҖ” detectar JSON encapsulado como string
if (typeof raw === "string" && raw.includes('"market_research_raw": "{')) {
  try {
    const outer = JSON.parse(raw);
    if (typeof outer.market_research_raw === "string") {
      raw = outer.market_research_raw;
    }
  } catch (e) {}
}

// рҹ”Ҙ HARDEN 2 вҖ” evitar erro de agent travado
if (typeof raw === "string" && raw.toLowerCase().includes("agent stopped")) {
  return [{
    json: {
      market_research_raw: null,
      _error: "Agent stopped (max iterations)"
    }
  }];
}

// 3. Limpeza de markdown e sujeira
let cleaned = String(raw)
  .trim()
  .replace(/```json/gi, "")
  .replace(/```javascript/gi, "")
  .replace(/```JSON/gi, "")
  .replace(/```/g, "")
  .trim();

// 4. Remover caracteres invisГӯveis problemГЎticos
cleaned = cleaned.replace(/\u00A0/g, " "); // Non-breaking space
cleaned = cleaned.replace(/\u200B/g, ""); // Zero-width space

// рҹ”Ҙ HARDEN 3 вҖ” tentar extrair JSON vГЎlido se tiver texto misturado
const firstBrace = cleaned.indexOf("{");
const lastBrace = cleaned.lastIndexOf("}");
if (firstBrace !== -1 && lastBrace !== -1) {
  cleaned = cleaned.slice(firstBrace, lastBrace + 1);
}

// 5. Tentar converter para JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  return [{
    json: {
      market_research_raw: cleaned,
      _error: "JSON.parse falhou",
      _details: err.message
    }
  }];
}

// рҹ”Ҙ HARDEN 4 вҖ” caso ainda venha como string
if (typeof parsed === "string") {
  try {
    parsed = JSON.parse(parsed);
  } catch (e) {}
}

// 6. Extrair corretamente o market_research_raw
let finalData = parsed.market_research_raw ? parsed.market_research_raw : parsed;

