    .filter(u => /linkedin\.com\/company\/[\w-]+/i.test(u))
    .map(u => { const m = u.match(/linkedin\.com(\/company\/[\w-]+)/i); return m ? 'https://www.linkedin.com' + m[1] : null; })
    .filter(Boolean)
    .sort((a, b) => a.length - b.length);
