  .filter(u => /youtube\.com\/@[\w-]+/i.test(u))
  .map(u => { const m = u.match(/youtube\.com\/@([\w-]+)/i); return m ? `https://www.youtube.com/@${m[1]}` : null; })
  .filter(Boolean);

if (ytFromUrl.length) {
