// --- Helpers ---------------------------------------------------------
const parseDate = (str) => {
  if (!str) return null;
  const months = {
    'janeiro':'01','fevereiro':'02','marГ§o':'03','abril':'04',
    'maio':'05','junho':'06','julho':'07','agosto':'08',
    'setembro':'09','outubro':'10','novembro':'11','dezembro':'12'
  };
  let m;
  m = str.match(/(\d+)\s+de\s+([a-zГЎГ ГЈГўГ©ГӘГӯГіГҙГөГәГјГ§]+)\s+de\s+(\d{4})/i);
  if (m) { const mo = months[m[2].toLowerCase()]; if (mo) return `${String(m[1]).padStart(2,'0')}/${mo}/${m[3]}`; }
  m = str.match(/(\d+)\s+([a-zГЎГ ГЈГўГ©ГӘГӯГіГҙГөГәГјГ§]+),\s+(\d{4})/i);
  if (m) { const mo = months[m[2].toLowerCase()]; if (mo) return `${String(m[1]).padStart(2,'0')}/${mo}/${m[3]}`; }
  m = str.match(/([a-zГЎГ ГЈГўГ©ГӘГӯГіГҙГөГәГјГ§]+)\s+(\d+),\s+(\d{4})/i);
  if (m) { const mo = months[m[1].toLowerCase()]; if (mo) return `${String(m[2]).padStart(2,'0')}/${mo}/${m[3]}`; }
  return null;
};

const toAbsoluteUrl = (url, base) => {
  if (!url) return null;
  if (/^https?:\/\//i.test(url)) return url;
  try {
    const b = new URL(base);
    return `${b.protocol}//${b.host}${url.startsWith('/') ? '' : '/'}${url}`;
  } catch { return url; }
};

const parseReadingTime = (str) => {
  if (!str) return null;
  const m = str.match(/(\d+)/);
  return m ? parseInt(m[1]) : null;
};

