    const coverM = [...lb.matchAll(/\[!\[[^\]]*\]\(([^)]+)\)\]\([^)]+\)/g)];
    const cover_image_url = coverM.length ? coverM[coverM.length - 1][1] : null;
    const catRe = /\[([^\]]+)\]\((https?:\/\/[^)]*\/categori[^)]+)\)/g;
    const categories = [...lb.matchAll(catRe)].map(c => ({ name: c[1].trim(), url: c[2].trim() }));
    const dateM = lb.match(/вҖў\s+(\d+\s+de\s+[a-zГЎГ ГЈГўГ©ГӘГӯГіГҙГөГәГјГ§]+\s+de\s+\d{4})/i);
    const published_at = dateM ? parseDate(dateM[1]) : null;
    const authorM = lf.match(/!\[[^\]]*\]\([^)]+\)\n+([^\n!\[#*вҖў\]]{2,40})\n/);
    let author = authorM ? authorM[1].trim() : null;
    if (!author || /^avatar$/i.test(author)) author = null;
    posts.push({ title: t.title, url: t.url, published_at, reading_time_minutes: null, categories, cover_image_url, author });
  });

} else if (isYamanFormat) {
  // PadrГЈo: imagem + categoria + [### TГӯtulo](/slug)
  const blocks = content.split(/(?=!\[)/);
  // Imagens do array separado (sem hero/opengraph)
  const postImages = imagesArr.filter(img =>
    !/hero|opengraph|logo|icon|avatar/i.test(img) &&
    /\.(webp|jpg|jpeg|png)/i.test(img)
  );
  let imgIdx = 0;

  const entryRe = /\[([^\]]*)\]\(\/blog\/categoria\/([^)]+)\)[,\s]*(?:\[([^\]]*)\]\(\/blog\/categoria\/([^)]+)\))?\s*\n+\[###\s+([^\]]+)\]\(([^)]+)\)/g;
  let em;
  while ((em = entryRe.exec(content)) !== null) {
    const title = em[5].trim();
    if (SKIP_TITLES.test(title)) continue;
    const url = toAbsoluteUrl(em[6], blogUrl);
    const categories = [{ name: em[1].trim(), url: toAbsoluteUrl(`/blog/categoria/${em[2]}`, blogUrl) }];
    if (em[3]) categories.push({ name: em[3].trim(), url: toAbsoluteUrl(`/blog/categoria/${em[4]}`, blogUrl) });
    posts.push({
      title,
      url,
      published_at: null,
      reading_time_minutes: null,
      categories,
      cover_image_url: postImages[imgIdx++] || null,
      author: null
    });
  }

} else if (isGenericFormat) {
  // Fallback genГ©rico: captura qualquer ## [Title](url)
  const re = /#{2,4}\s+\[([^\]]+)\]\(([^)]+)\)/g;
  let m;
  const seen = new Set();
  while ((m = re.exec(content)) !== null) {
    const title = m[1].trim();
    const url   = toAbsoluteUrl(m[2].trim(), blogUrl);
    if (SKIP_TITLES.test(title)) continue;
    if (seen.has(title)) continue;
    seen.add(title);
    // Tenta pegar categoria antes do tГӯtulo
    const before = content.slice(Math.max(0, m.index - 300), m.index);
    const catM = before.match(/\[([^\]]+)\]\(\/[^)]*categor[^)]*\)/i);
    const categories = catM ? [{ name: catM[1].trim(), url: toAbsoluteUrl(catM[0].match(/\(([^)]+)\)/)[1], blogUrl) }] : [];
    posts.push({ title, url, published_at: null, reading_time_minutes: null, categories, cover_image_url: null, author: null });
  }
}

// --- Resultado (apenas os 6 mais recentes) ---------------------------
return [{
  json: {
    source_type: 'blog_posts',
    blog_url: blogUrl,
    scraped_at: new Date().toISOString(),
    total_found: posts.length,
    total_returned: Math.min(posts.length, 6),
    posts: posts.slice(0, 6)
  }
}];
